const item = $input.item.json;

const fromRaw = item.from || '';
const emailMatch = fromRaw.match(/<(.+?)>/) || [null, fromRaw];
const emailAddress = emailMatch[1] || fromRaw;
const domain = emailAddress.includes('@') ? emailAddress.split('@')[1].toLowerCase() : 'sconosciuto';
const nomeMittente = fromRaw.includes('<') ? fromRaw.split('<')[0].trim().replace(/"/g, '') : emailAddress;

const attachments = item.attachments || [];

return {
  json: {
    threadId: item.threadId,
    messageId: item.id,
    fromRaw,
    emailAddress,
    domain,
    nomeMittente,
    oggetto: item.subject || '(nessun oggetto)',
    snippet: item.snippet || '',
    data: item.date || new Date().toISOString(),
    hasAttachments: attachments.length > 0,
    numAllegati: attachments.length,
    attachments
  }
};

// Unisce i dati dell'email con la risposta Python
const pythonResult = $input.item.json;
const metadati = $('🔍 Estrai Metadati').item.json;

return {
  json: {
    ...metadati,
    // Risultato Python
    py_categoria:      pythonResult.categoria,
    py_sottocategoria: pythonResult.sottocategoria,
    py_confidence:     pythonResult.confidence,
    py_needs_ai:       pythonResult.needs_ai,
    py_method:         pythonResult.method,
    py_label_gmail:    pythonResult.label_gmail,
    py_priorita:       pythonResult.priorita
  }
};

