// Percorso A: Python ha classificato con alta confidenza
const item = $input.item.json;

const labelMap = {
  'AI-TECH':          'Label_7902931228053036763',
  'EBIS':             'Label_6670020163438591806',
  'VIAGGI':           'Label_3926604745380117165',
  'FATTURE-RICEVUTE': 'Label_1756272630694179019',
  'ACQUISTI-ONLINE':  'Label_5446396601638215443',
  'PERSONALE':        'Label_6458834741239452187',
  'IMMOBILIARE':      'Label_7609977426367813609',
  'ALTRO':            'Label_17396968883308128'
};

const categoria     = item.py_categoria;
const sottocartella = item.py_sottocategoria;
const cartellaBase  = 'Email Organizer';
const percorso      = `${cartellaBase}/${categoria}/${sottocartella}`;

return { json: {
  ...item,
  categoria,
  sottocartella,
  priorita:       item.py_priorita,
  labelId:        labelMap[categoria] || 'Label_17396968883308128',
  label_gmail:    item.py_label_gmail,
  percorsoGDrive: percorso,
  percorsoICloud: `/Users/jacopo/Library/Mobile Documents/com~apple~CloudDocs/${percorso}`,
  classificatore: 'python',
  confidence:     item.py_confidence
}};

// Percorso B: OpenAI ha classificato
const aiResponse = $input.item.json;
const metadati = $('🔗 Merge Dati Python').item.json;

const labelMap = {
  'AI-TECH':          'Label_7902931228053036763',
  'EBIS':             'Label_6670020163438591806',
  'VIAGGI':           'Label_3926604745380117165',
  'FATTURE-RICEVUTE': 'Label_1756272630694179019',
  'ACQUISTI-ONLINE':  'Label_5446396601638215443',
  'PERSONALE':        'Label_6458834741239452187',
  'IMMOBILIARE':      'Label_7609977426367813609',
  'ALTRO':            'Label_17396968883308128'
};

let classificazione;
try {
  const rawText = aiResponse.choices[0].message.content;
  const cleanText = rawText.replace(/```json|```/g, '').trim();
  classificazione = JSON.parse(cleanText);
  if (!classificazione.categoria || !classificazione.sottocartella) throw new Error('Campi mancanti');
} catch(e) {
  classificazione = { categoria: 'ALTRO', sottocartella: 'da-valutare', priorita: 'bassa', label_gmail: 'ALTRO/da-valutare' };
}

const cartellaBase = 'Email Organizer';
const percorso = `${cartellaBase}/${classificazione.categoria}/${classificazione.sottocartella}`;

return { json: {
  ...metadati,
  categoria:      classificazione.categoria,
  sottocartella:  classificazione.sottocartella,
  priorita:       classificazione.priorita,
  labelId:        labelMap[classificazione.categoria] || 'Label_17396968883308128',
  label_gmail:    classificazione.label_gmail,
  percorsoGDrive: percorso,
  percorsoICloud: `/Users/jacopo/Library/Mobile Documents/com~apple~CloudDocs/${percorso}`,
  classificatore: 'openai',
  confidence:     null
}};

const item = $input.item.json;
const attachments = item.attachments || [];
if (attachments.length === 0) return [];
return attachments.map(att => ({ json: {
  categoria:      item.categoria,
  sottocartella:  item.sottocartella,
  percorsoGDrive: item.percorsoGDrive,
  percorsoICloud: item.percorsoICloud,
  prefissoFile:   `${new Date().getFullYear()}-${String(new Date().getMonth()+1).padStart(2,'0')}_${item.sottocartella}`,
  messageId:      item.messageId,
  attachmentName: att.filename || 'allegato',
  attachmentId:   att.attachmentId || att.id,
  nomeFileFinale: `${new Date().getFullYear()}-${String(new Date().getMonth()+1).padStart(2,'0')}_${item.sottocartella}_${att.filename || 'allegato'}`
}}));

const fs = require('fs');
const datiAllegato = $('📂 Espandi Allegati').item.json;
const percorsoICloud = datiAllegato.percorsoICloud;
const nomeFile = datiAllegato.nomeFileFinale;
const percorsoCompleto = `${percorsoICloud}/${nomeFile}`;
try {
  fs.mkdirSync(percorsoICloud, { recursive: true });
  const fileData = $input.item.binary?.data;
  if (fileData) {
    fs.writeFileSync(percorsoCompleto, Buffer.from(fileData.data, 'base64'));
  }
  return [{ json: { success: true, percorso: percorsoCompleto } }];
} catch(e) {
  return [{ json: { success: false, errore: e.message } }];
}

const item = $input.item.json;
console.log(`✅ Email processata | classificatore: ${item.classificatore} | confidence: ${item.confidence ?? 'N/A (OpenAI)'} | ${item.categoria}/${item.sottocartella}`);
return [{ json: {
  status: 'completato',
  mittente: item.emailAddress,
  categoria: item.categoria,
  sottocartella: item.sottocartella,
  classificatore: item.classificatore,
  confidence: item.confidence,
  timestamp: new Date().toISOString()
}}];
